function autoFormatTime(T){let i=T['value']['replace'](/\D/g,'');switch(i['length']>0x4&&(i=i['slice'](0x0,0x4)),i['length']){case 0x0:case 0x1:case 0x2:T['value']=i;break;case 0x3:if(parseInt(i['slice'](0x0,0x2),0xa)<=0x17)T['value']=i['slice'](0x0,0x2)+':'+i['slice'](0x2);else{let s=i['slice'](0x0,0x1)['padStart'](0x2,'0'),f=i['slice'](0x1);T['value']=s+':'+f;}break;case 0x4:let Z=i['slice'](0x0,0x2),Y=i['slice'](0x2);T['value']=Z+':'+Y;}}function transformTimeValue(T){let i=T['trim']();if(/^\d{2}$/['test'](i))return i[0x0]['padStart'](0x2,'0')+':'+i[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](i))return 0x3===i['length']?parseInt(i['slice'](0x0,0x2),0xa)<=0x17?i['slice'](0x0,0x2)+':'+i['slice'](0x2):i['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+i['slice'](0x1):i['slice'](0x0,0x2)+':'+i['slice'](0x2);if(i['includes'](':')){let [Z,Y]=i['split'](':');return Y||(Y='00'),Z=Z['padStart'](0x2,'0'),Y=Y['padStart'](0x2,'0'),Z+':'+Y;}return i;}